let x, y, px, py;
function setup() {
  createCanvas(400, 400);
  x = random(width);
  y = random(height);
  px = x;
  py = y;
}
function draw() {
  line(x, y, px, py);
  px = x;
  py = y;
  x += random(-1, 1);
  y += random(-1, 1);
}

class Walker {
  constructor() {
    this.x = random(width);
    this.y = random(height);
    this.px = this.x;
    this.py = this.y;
  }
  update() {
    this.px = this.x;
    this.py = this.y;
    this.x += random(-4, 4);
    this.y += random(-4, 4);
  }
  display() {
    line(this.x, this.y, this.px, this.py);
  }
}

for (let walker of arr) {
  walker.update();
  walker.display();
}
